body:
From UVM tests/80examples/20codec, below gives

```
%Error: Internal Error: t/t_0.v:33:26: ../V3Width.cpp:3515: MemberSel of non-variable
```

<details>
<summary>Example</summary>

```
interface vip_tx_if (
    output reg Tx
);
endinterface

interface vip_if (
    output reg Tx
);
  vip_tx_if tx (Tx);
endinterface

package vip_pkg;
  typedef virtual vip_if vip_vif;
  typedef virtual vip_tx_if vip_tx_vif;

  class vip_agent;
    vip_vif vif;
  endclass

  class vip_driver;
    vip_vif vif;
    vip_tx_vif tx_vif;
    virtual function void build_phase();
      vip_agent agent;
      // dtype(agent.vif) -> vip_vif -> vip_if
      vif = agent.vif;
      tx_vif = agent.vif.tx;
    endfunction
  endclass

endpackage

module t;
endmodule
```
</details>

